 4→import { useAuth } from '../../Context/useAuth';
 5→import { useTheme } from '../../Context/useTheme';
 6→import VerifiedBadge from '../Badge/VerifiedBadge';
 7→
 8→const Sidebar = ({links}) =>{
 9→    const {user, session, signOut} = useAuth();
10→    const {theme, toggleTheme} = useTheme();
11→    const navigate = useNavigate(null)
12→    const location = useLocation();
13→    
14→    // const extractPath = (path) =>{
15→    //     let segments = path.split('/');
16→    //     segments.shift();
17→
18→    //     const segment = segments[0];
19→    //     return `/${segment}`;
20→    // }
21→    // const path = extractPath(location.pathname)
22→    const userData = user?.userData?.[0];
23→    return(
24→        <>
25→        <div className='side-bar-container'>
26→            <div className='sidebar-header'>
27→                Iskrib
28→            </div>
29→            {links.map((link, index) => {   
30→                return(
31→                <div className={link.className ? link.className : location.pathname === link.path ? 'sidebar-links-active' : 'sidebar-links'} onClick={link.action} key={index}>
32→                    <div className='icon-container'>
33→                        {link.icon}
34→                        {link.notifCount && (
35→                            <div className='notification-count'>{link.notifCount}</div>
36→                        )}
37→                    </div>   
38→
39→                    {link.label}
40→                </div>
41→                )
42→            })}
43→            <div className='sidebar-theme-toggle' onClick={toggleTheme}>
44→                <span>{theme === 'dark' ? 'Light mode' : 'Dark mode'}</span>
45→                <div className={`theme-toggle-track ${theme === 'dark' ? 'active' : ''}`}>
46→                    <div className='theme-toggle-thumb'/>
47→                </div>
48→            </div>
49→            <div className='sidebar-user-container'>
50→                {userData && (
51→                    <>
52→                    <div className='sidebar-avatar-container'>
53→                        <img loading='lazy' className='sidebar-avatar' src={userData.image_url || '/assets/profile.jpg'} alt={`${userData?.name || "User"} profile picture`} />
54→
55→                        <div className='sidebar-metadata-container'>
56→                            <span className='sidebar-name'>{userData.name}<VerifiedBadge badge={userData.badge} size={14} /></span>
57→                            <span className='sidebar-email'>{session?.user.email}</span>
58→                        </div>
59→                    </div>
60→                    <div className='side-bar-logout-container'>
61→                        <div onClick={signOut}>
62→                            Sign Out
63→                        </div>
64→                    </div>
65→                    </>                  
66→                )}
67→            </div>
68→        </div>
69→        </>
70→    )
71→}
72→export default Sidebar;
