/* ── Card ── */
.cards{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: center;
    width: 99%;
    max-width: 100%;
    min-height: fit-content;
    background-color: var(--bg-card);
    border: 1px solid var(--border-card);
    border-radius: 12px;
    overflow: hidden;
    cursor: pointer;
    transition: box-shadow 0.25s ease, transform 0.25s ease;
}
.cards:hover{
    box-shadow: 0 6px 24px rgba(0, 0, 0, 0.07);
    transform: translateY(-2px);
}

.bookmarked-content-message-container{
    position: absolute;
    top: 100px;
    background-color: rgb(72, 208, 135);
    color: rgb(255, 255, 255);
    font-size: 0.78rem;
    font-weight: 600;
    padding: 0.45rem 1rem;
    border-radius: 8px;
    width: fit-content;
    z-index: 11;
    transition: ease-in-out 0.2s;
}

/* ── Banner image ── */
.card-image-banner{
    width: 100%;
    max-height: 220px;
    object-fit: cover;
    display: block;
    border-bottom: 1px solid var(--border-card);
    transition: opacity 0.2s ease;
}
.cards:hover .card-image-banner{
    opacity: 0.95;
}

/* ── Card content area ── */
.card-content{
    display: flex;
    flex-direction: column;
    gap: 0.8rem;
    width: 100%;
    padding: 1rem 1.15rem 0.6rem 1.15rem;
    box-sizing: border-box;
}

/* ── User info row ── */
.user-info{
    display: flex;
    justify-content: space-between;
    align-items: center;
}
.user-info-child-container{
    display: flex;
    align-items: center;
    height: 100%;
    gap: 0.4rem;
    width: fit-content;
}
.user-avatar-container{
    display: flex;
    align-items: center;
    justify-content: center;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
}
.user-info-avatar{
    width: 22px;
    height: 22px;
    border-radius: 50%;
    object-fit: cover;
}
.user-avatar-container.avatar-ring-legend{
    border-radius: 50%;
    border: 2px solid #FFD700;
    box-shadow:
        0 0 6px 1px rgba(255, 215, 0, 0.5),
        0 0 12px 2px rgba(255, 215, 0, 0.35),
        0 0 20px 4px rgba(255, 215, 0, 0.2);
    animation: glow-legend 2s ease-in-out infinite alternate;
}
.user-avatar-container.avatar-ring-og{
    border-radius: 50%;
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 6px 1px rgba(155, 89, 255, 0.5),
        0 0 12px 2px rgba(155, 89, 255, 0.35),
        0 0 20px 4px rgba(155, 89, 255, 0.2);
    animation: glow-og 2s ease-in-out infinite alternate;
}

@keyframes glow-legend {
    from {
        box-shadow:
            0 0 6px 1px rgba(255, 215, 0, 0.5),
            0 0 12px 2px rgba(255, 215, 0, 0.35),
            0 0 20px 4px rgba(255, 215, 0, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(255, 215, 0, 0.6),
            0 0 16px 4px rgba(255, 215, 0, 0.4),
            0 0 24px 6px rgba(255, 215, 0, 0.25);
    }
}

@keyframes glow-og {
    from {
        box-shadow:
            0 0 6px 1px rgba(155, 89, 255, 0.5),
            0 0 12px 2px rgba(155, 89, 255, 0.35),
            0 0 20px 4px rgba(155, 89, 255, 0.2);
    }
    to {
        box-shadow:
            0 0 8px 2px rgba(155, 89, 255, 0.6),
            0 0 16px 4px rgba(155, 89, 255, 0.4),
            0 0 24px 6px rgba(155, 89, 255, 0.25);
    }
}
.user-name-container{
    display: flex;
    align-items: center;
    gap: 0.2rem;
}
.user-newsfeed-name{
    font-family: var(--font-ui);
    font-size: 0.78rem;
    font-weight: 600;
    letter-spacing: 0.005rem;
    margin: 0;
    padding: 0;
    cursor: pointer;
    color: var(--text-secondary);
    transition: color 0.15s ease;
}
.user-newsfeed-name:hover{
    text-decoration: underline;
    color: var(--accent-sage);
}
.name-info-separator{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    color: var(--text-separator);
    font-size: 0.4rem;
    user-select: none;
}
.user-info-email-container{
    display: none;
}
.user-info-email{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-date-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
}
.user-post-privacy{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    cursor: default;
    user-select: none;
    color: var(--text-heading);
}
.user-post-date{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.75rem;
    font-weight: 400;
    color: var(--text-faint);
}
.user-post-settings{
    position: relative;
    display: flex;
    flex-direction: column;
    justify-self: flex-end;
    width: fit-content;
    height: fit-content;
    cursor: pointer;
    user-select: none;
    color: var(--text-heading);
}
.setting-modal{
    display: flex;
    justify-content: center;
    align-items: center;
    position: absolute;
    right: 25px;
    bottom: 10px;
    width: 200px;
    height: 100px;
    border-radius: 10px;
    z-index: 200;
    background-color: var(--bg-elevated);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
    border: 1px solid var(--border-card);
}

/* ── Content (title + text) ── */
.content-container{
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    user-select: none;
    gap: 0.5rem;
}
.feed-text-content-container{
    display: flex;
    flex-direction: column;
    width: 100%;
    height: 100%;
    justify-content: flex-start;
    align-items: flex-start;
    gap: 0.35rem;
}
.feed-title-content{
    display: flex;
    justify-content: center;
    align-items: center;
}
.cards.is-canvas-card .feed-title-content{
    flex-direction: row;
    justify-content: flex-start;
    gap: 0.45rem;
}
.feed-title{
    margin: 0;
    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.1rem;
    font-weight: 700;
    line-height: 1.45;
    letter-spacing: -0.025rem;
    color: var(--text-heading);
}
.feed-text-content{
    padding: 0;
    margin: 0;
    font-family: var(--font-serif);
    font-weight: 400;
    color: var(--text-body);
    line-height: 1.7;
    font-size: 0.88rem;
    letter-spacing: 0.005rem;
}

.canvas-card-actions{
    display: flex;
    flex-wrap: wrap;
    gap: 0.42rem;
    width: 100%;
    margin-top: -0.1rem;
}

.canvas-card-action-btn{
    border: 1px solid var(--border-card);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    border-radius: 999px;
    padding: 0.3rem 0.65rem;
    font-size: 0.68rem;
    font-weight: 620;
    cursor: pointer;
    transition: border-color 0.2s ease, background 0.2s ease, color 0.2s ease;
}

.canvas-card-action-btn:hover{
    border-color: var(--accent-sage);
    color: var(--accent-sage);
}

.canvas-card-action-btn.is-remix{
    border-color: color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
    color: var(--accent-purple);
}

/* ── Icon bar ── */
.card-icons-container{
    display: flex;
    flex-wrap: wrap;
    width: 100%;
    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
    min-height: 22px;
    align-items: center;
    justify-content: flex-start;
    gap: 0.5rem;
    box-sizing: border-box;
    border-top: 1px solid var(--border-card);
}
#card-icons{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.35rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
#card-icons-view{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.1rem;
    border-radius: 50%;
    transition: background-color 0.2s ease;
    gap: 0.3rem;
}
.card-icons{
    display: flex;
    width: fit-content;
    height: fit-content;
    justify-content: center;
    align-items: center;
}
.icon-container{
    display: flex;
    justify-content: center;
    align-items: center;
}
.icon-container p{
    font-family: var(--font-ui);
}

.like-button:hover .svg-like path{
    fill: rgb(255, 116, 116);
}
.like-button:hover{
    background-color: rgba(255, 161, 161, 0.12);
}
.comment-button:hover{
    background-color: rgba(107, 143, 113, 0.12);
}
.comment-button:hover .svg-comment path{
    fill: var(--accent-sage);
}
.bookmark-button:hover{
    background-color: rgba(245, 158, 11, 0.12);
}
.bookmark-button:hover .svg-bookmark path{
    fill: var(--accent-amber);
}

/* ── Reading time pill ── */
.reading-time-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.2rem 0.7rem;
    background-color: var(--bg-pill);
    border: 1px solid var(--border-card);
    border-radius: 10px;
    margin-left: auto;
}
.reading-time-text{
    padding: 0;
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.62rem;
    font-weight: 550;
    color: var(--accent-sage);
    letter-spacing: 0.01rem;
}

.sample-content-show{
    width: 100%;
    height: 100%;
    background-color: var(--bg-primary);
    z-index: 10;
}

/* ── Mobile responsive ── */
@media (max-width: 480px){
    .feed-search-shell{
        display: none;
    }
    .search-shell{
        top: 56px;
    }
    .search-top-bar{
        padding: 0.5rem 0.5rem 0.55rem 0.5rem;
        gap: 0.4rem;
    }
    .search-input{
        font-size: 0.8rem;
        padding: 0.5rem 0.75rem 0.5rem 2.1rem;
        border-radius: 8px;
    }
    .search-icon{
        left: 0.7rem;
        width: 14px;
        height: 14px;
    }
    .search-clear-btn{
        font-size: 0.64rem;
        padding: 0.32rem 0.52rem;
        border-radius: 6px;
    }
    .search-freedom-wall-btn{
        font-size: 0.6rem;
        padding: 0.3rem 0.45rem;
        border-radius: 6px;
    }
    .search-mode-pill{
        font-size: 0.58rem;
        padding: 0.28rem 0.44rem;
        border-radius: 6px;
    }
    .search-gallery-hint{
        margin: 0 0.5rem 0.42rem 0.5rem;
        font-size: 0.6rem;
        padding: 0.3rem 0.5rem;
        border-radius: 6px;
    }
    .search-suggestions-dropdown{
        left: 0.5rem;
        right: 0.5rem;
        top: calc(100% - 0.1rem);
        max-height: 260px;
        border-radius: 8px;
    }
    .search-suggestion-item{
        padding: 0.52rem 0.7rem;
        border-left-width: 2px;
    }
    .search-suggestion-title{
        font-size: 0.76rem;
    }
    .search-suggestion-meta{
        font-size: 0.62rem;
    }
    .postcards-parent-container {
        position: relative;
        top: 60px;
        display: flex;
        flex-direction: column;
        align-items: center;
        width: 100%;
        margin-bottom: 1rem;
        gap: 12px;
        padding: 0 10px;
        box-sizing: border-box;
    }
    .postcards-parent-loading-container {
        position: relative;
        top: 60px;
        display: flex;
        justify-content: center;
        align-items: center;
        flex-direction: column;
        width: 100%;
        height: 100vh;
    }
    .cards{
        border-radius: 10px;
        overflow: visible;
        max-width: 100%;
        box-sizing: border-box;
    }
    .card-image-banner{
        max-height: 160px;
        border-radius: 10px 10px 0 0;
    }
    .card-content{
        width: 100%;
        padding: 0.75rem 0.75rem 0.4rem 0.75rem;
        box-sizing: border-box;
    }
    .content-container {
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        user-select: none;
        gap: 0.3rem;
    }
    .feed-title{
        font-size: 0.92rem;
        line-height: 1.3;
    }
    .feed-text-content {
        padding: 0;
        margin: 0;
        font-family: var(--font-serif);
        font-weight: 400;
        font-size: 0.78rem;
        color: var(--text-body);
        line-height: 1.5;
    }
    .canvas-card-actions{
        gap: 0.34rem;
    }
    .canvas-card-action-btn{
        font-size: 0.64rem;
        padding: 0.26rem 0.55rem;
    }

    /* Footer: two explicit rows — author top, actions bottom */
    .card-icons-container{
        display: flex;
        flex-wrap: wrap;
        width: 100%;
        padding: 0.5rem 0.75rem 0.7rem 0.75rem;
        min-height: auto;
        height: auto;
        align-items: center;
        justify-content: flex-start;
        gap: 0.4rem;
        row-gap: 0.5rem;
        box-sizing: border-box;
        overflow: hidden;
    }

    /* Row 1: Author info — full width, forces wrap */
    .card-icons-container .user-info-child-container{
        display: flex;
        align-items: center;
        flex: 0 0 100%;
        gap: 0.3rem;
        padding-bottom: 0.25rem;
        border-bottom: 0.5px solid var(--border-card);
        margin-bottom: 0.1rem;
    }
    .card-icons-container .user-info-child-container .user-newsfeed-name{
        font-family: var(--font-ui);
        font-size: 0.72rem;
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
        max-width: 120px;
    }
    .card-icons-container .user-info-child-container .user-post-date{
        font-family: var(--font-ui);
        font-size: 0.6rem;
        white-space: nowrap;
    }
    .card-icons-container .user-info-child-container .user-info-avatar{
        width: 20px;
        height: 20px;
    }

    /* Row 2: Action icons — guaranteed visible */
    .icon-container{
        display: flex !important;
        align-items: center;
        flex-shrink: 1;
        min-width: 0;
        min-height: 24px;
        visibility: visible;
    }

    /* Base icon button styles (covers like, comment, bookmark) */
    .icon-container .like-button,
    .icon-container .comment-button,
    .icon-container .bookmark-button{
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.3rem;
        border-radius: 50%;
        transition: background-color 0.2s ease;
    }

    .svg-like{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-comment{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    .svg-bookmark{
        width: 18px !important;
        height: 18px !important;
        display: block;
    }
    #card-icons{
        display: flex;
        align-items: center;
        padding: 0.3rem;
        gap: 0.15rem;
    }
    #card-icons-view{
        display: flex;
        align-items: center;
    }
    #card-icons-view svg{
        width: 22px;
        height: 22px;
    }
    .icon-container p{
        font-family: var(--font-ui);
        font-size: 0.68rem !important;
        white-space: nowrap;
        margin: 0 !important;
        padding: 0 !important;
    }

    /* Reading time pill — always visible, pushed right */
    .reading-time-container{
        display: flex !important;
        visibility: visible;
        margin-left: auto;
        padding: 0.2rem 0.6rem;
        flex-shrink: 0;
        min-width: fit-content;
    }
    .reading-time-text{
        font-size: 0.58rem;
        white-space: nowrap;
    }

    .user-post-settings{
        flex-shrink: 0;
        color: var(--text-heading);
    }
    .user-post-settings svg{
        width: 20px;
        height: 20px;
    }
    .setting-modal{
        right: 0;
        bottom: 25px;
        width: 180px;
        height: 80px;
        font-size: 0.75rem;
    }
    .toolbar {
        display: flex;
        justify-content: center;
        height: 100%;
        width: 100%;
    }
    .toolbar-bttns {
        display: flex;
        width: 16px;
        height: 16px;
        justify-content: center;
        align-items: center;
        padding: 0.5rem;
        border-radius: 10px;
        cursor: pointer;
        transition: ease-in-out 0.1s;
        user-select: none;
    }
    .editor-save-bttn {
        display: flex;
        justify-content: center;
        align-items: center;
        padding: 0.2rem 0.8rem;
        font-size: 0.8rem;
        border-radius: 15px;
        margin-right: 1rem;
        background-color: rgb(255, 255, 255);
        color: rgb(4, 20, 29);
        font-weight: 600;
        cursor: pointer;
        border: hidden;
    }

}

