file.content:
.newsfeed-header{
}
.search-shell{
    position: sticky;
    top: 0;
    z-index: 14;
    align-self: stretch;
    width: 100%;
    max-width: 100%;
}
.search-top-bar{
    position: relative;
    z-index: 12;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
    box-sizing: border-box;
    background: var(--bg-primary);
    border-bottom: 1px solid var(--border-card);
}
.search-input-wrap{
    position: relative;
    display: flex;
    align-items: center;
    flex: 1;
}
.search-icon{
    position: absolute;
    left: 0.85rem;
    width: 15px;
    height: 15px;
    color: var(--text-faint);
    pointer-events: none;
    transition: color 0.25s ease, transform 0.25s ease;
}
.search-input-wrap:focus-within .search-icon{
    color: var(--accent-sage);
    transform: scale(1.08);

